window.MEDICAL_DATA = {"manifest":{"id":"medical","title":"Medical Emergencies Review — Medical, Behavioral & Geriatric","subtitle":"The Ultimate Provider Course Reviewer","version":"1.0.0","edition":"Aligned with current GINA, ADA, AHA/ASA stroke, and DSM-5-TR guidance; scoped to the NREMT Paramedic Medical/OB-GYN domain","description":"A comprehensive, self-contained study reviewer for adult medical, behavioral, and geriatric emergencies. Each chapter includes a concise summary, clinical pearls, red flags, common mistakes, memory aids, high-yield flashcards, exam-style quiz questions with rationales, realistic scenarios, and comparison tables. Designed for EMTs, paramedics, and nursing/allied-health students preparing for licensing-style cognitive exams (Prometric-administered, NREMT-aligned).","icon":"stethoscope","color":"#2563eb","accentColor":"#e06090","estimatedHours":10,"difficulty":"Intermediate","certification":"EMT/Paramedic licensing exam preparation (Prometric-administered, NREMT-aligned)","examLink":"https://www.nremt.org/","audience":["EMT","Paramedic","Nursing Student","Allied Health Student"],"prerequisites":["BLS provider competency","Basic patient assessment (see EMPACT reviewer)"],"contentTypes":["summary","flashcards","quizzes","scenarios","algorithms","tables"],"chapters":[{"id":"c01","number":1,"title":"Neurological Emergencies I — Stroke & TIA","section":"Neurological","difficulty":"Intermediate"},{"id":"c02","number":2,"title":"Neurological Emergencies II — Seizures & Altered Mental Status","section":"Neurological","difficulty":"Intermediate"},{"id":"c03","number":3,"title":"Endocrine Emergencies — Hypoglycemia, DKA & HHS","section":"Endocrine","difficulty":"Advanced"},{"id":"c04","number":4,"title":"Respiratory Medical Emergencies — Asthma & COPD","section":"Respiratory","difficulty":"Intermediate"},{"id":"c05","number":5,"title":"Obstetric Medical Emergencies — Preeclampsia & Eclampsia","section":"Medical/OB","difficulty":"Intermediate"},{"id":"c06","number":6,"title":"Behavioral Emergencies I — Assessment & De-escalation","section":"Behavioral","difficulty":"Beginner to Intermediate"},{"id":"c07","number":7,"title":"Behavioral Emergencies II — Psychotic & Mood Disorders","section":"Behavioral","difficulty":"Intermediate"},{"id":"c08","number":8,"title":"Behavioral Emergencies III — Personality, Substance-Related & High-Risk Presentations","section":"Behavioral","difficulty":"Advanced"},{"id":"c09","number":9,"title":"Geriatric Emergencies I — Delirium vs. Dementia & Atypical Presentations","section":"Geriatric","difficulty":"Intermediate"},{"id":"c10","number":10,"title":"Geriatric Emergencies II — Polypharmacy, Falls & Elder Abuse Recognition","section":"Geriatric","difficulty":"Intermediate"},{"id":"c11","number":11,"title":"Toxicological & Environmental Medical Presentations","section":"Toxicology","difficulty":"Intermediate"},{"id":"c12","number":12,"title":"Sepsis, GI/Renal Emergencies & General Medical Red Flags","section":"Medical","difficulty":"Intermediate"}]},"chapters":{"c01":{"id":"c01","title":"Neurological Emergencies I — Stroke & TIA","shortTitle":"Stroke & TIA","estimatedStudyTime":30,"difficulty":"Intermediate","learningObjectives":["Distinguish stroke from TIA and explain why prehospital care treats both as time-critical.","Differentiate ischemic from hemorrhagic stroke and its field-relevant implications.","Apply a validated prehospital stroke scale to recognize likely stroke.","Recognize findings suggestive of a large-vessel occlusion (LVO) stroke.","Describe field priorities: last-known-well time, glucose check, and rapid transport/notification."],"summary":[{"title":"Stroke vs. TIA — Same Urgency, Different Duration","content":"A stroke is an acute disruption of blood flow to the brain causing neurologic deficit; a transient ischemic attack (TIA) produces the same type of deficit but resolves completely, classically within minutes to an hour, without lasting tissue injury on imaging. Because a TIA cannot be reliably distinguished from an evolving stroke in the field — and because TIA carries a significant short-term risk of a subsequent completed stroke — both are treated with the same urgency: rapid recognition, rapid transport, and rapid hospital notification."},{"title":"Ischemic vs. Hemorrhagic Stroke","content":"Ischemic stroke (the large majority of strokes) results from a clot or other obstruction blocking blood flow; hemorrhagic stroke results from bleeding into or around brain tissue. The two cannot be reliably distinguished in the field by symptoms alone — both cause focal neurologic deficits — which is why field care focuses on rapid recognition and transport rather than attempting to guess the stroke type, leaving that determination to hospital imaging."},{"title":"Validated Prehospital Stroke Scales","content":"The Cincinnati Prehospital Stroke Scale (CPSS) checks three findings — facial droop, arm drift, and speech abnormality — and is widely taught as the entry-level prehospital screening tool. Other validated scales add sensitivity for detecting a large-vessel occlusion (LVO), which may change the destination decision in systems with endovascular-capable centers: the Los Angeles Prehospital Stroke Screen (LAPSS), RACE (Rapid Arterial oCclusion Evaluation), and FAST-ED (which adds eye deviation and denial/neglect to the FAST components). Current stroke guidance continues to endorse using a validated scale for prehospital stroke recognition and LVO screening, with the specific scale and any destination threshold set by the local EMS system."},{"title":"Recognizing Possible Large-Vessel Occlusion","content":"Findings that raise suspicion for LVO stroke — beyond a simple facial droop/arm drift/speech finding — include gaze deviation toward one side, severe unilateral weakness affecting both the face and arm together, and neglect/denial of the deficit (the patient not recognizing or acknowledging a weak limb). Systems with access to an endovascular-capable stroke center may use an LVO-screening scale to decide whether to bypass a closer, non-endovascular-capable hospital, per local protocol."},{"title":"Field Priorities","content":"Once stroke is suspected: determine and document the last-known-well time precisely (this drives eligibility for time-sensitive hospital treatments), check blood glucose (hypoglycemia is a well-known stroke mimic and is rapidly correctable), perform a validated stroke scale, and transport rapidly with early hospital notification (a 'stroke alert') so the receiving facility can prepare. Avoid delaying transport for a full neurologic exam beyond the screening scale — time is the central variable in stroke outcome."}],"clinicalPearls":["TIA and stroke get the same field urgency — a resolved deficit does not rule out a serious ongoing process.","Field care cannot reliably distinguish ischemic from hemorrhagic stroke — treat both as time-critical and let hospital imaging sort it out.","Always check glucose in a suspected stroke patient — hypoglycemia is a correctable stroke mimic.","Last-known-well time is one of the single most important pieces of information you can gather and document."],"redFlags":["Any new focal neurologic deficit (facial droop, arm drift, speech abnormality), even if it has since resolved.","Gaze deviation, severe unilateral face+arm weakness, or neglect of a weak limb — possible LVO.","An unclear or unknown last-known-well time — document what is known and keep gathering it en route."],"commonMistakes":["Dismissing a resolved deficit (possible TIA) as no longer urgent.","Failing to check glucose before assuming a deficit is purely neurologic.","Delaying transport to complete an extensive neurologic exam instead of a rapid validated screening scale."],"memoryAids":["FAST: Face, Arm, Speech, Time.","TIA = stroke symptoms that resolved, not a stroke that didn't happen — same urgency.","Glucose first — a fast, correctable stroke mimic.","Time is brain — last-known-well time drives everything downstream."],"decisionTrees":[{"title":"Suspected Stroke Field Approach","content":"Focal neurologic deficit noted (current or recently resolved)\n  → Check blood glucose → treat hypoglycemia per protocol if present, reassess\n  → Determine and document last-known-well time precisely\n  → Perform validated prehospital stroke scale (e.g., CPSS ± LVO-screening scale per local protocol)\n  → Positive screen → early hospital notification ('stroke alert'), rapid transport per local destination protocol (nearest stroke center vs. EVT-capable center bypass, per LVO screen and system design)\n  → Continue serial reassessment en route; do not delay transport for an extensive exam"}],"references":["2026 AHA/ASA Guideline for the Early Management of Patients With Acute Ischemic Stroke","Cincinnati Prehospital Stroke Scale (CPSS); RACE and FAST-ED as examples of LVO-screening scales"]},"c02":{"id":"c02","title":"Neurological Emergencies II — Seizures & Altered Mental Status","shortTitle":"Seizures & AMS","estimatedStudyTime":30,"difficulty":"Intermediate","learningObjectives":["List common causes of adult seizures and altered mental status.","Describe the postictal state and distinguish it from ongoing seizure activity.","Define status epilepticus and describe its field management priorities.","Apply a structured framework (AEIOU-TIPS) for reversible causes of altered mental status.","Describe field priorities for a seizing or newly altered adult patient."],"summary":[{"title":"Not All Seizures Are Life-Threatening","content":"Most adult seizures are brief, self-limited events that stop on their own within a couple of minutes. Common causes include idiopathic epilepsy (a known seizure disorder, often with medication non-compliance as a trigger), hypoglycemia, head trauma, intoxication or withdrawal (especially alcohol withdrawal), fever (more classically pediatric but relevant in adults with underlying infection), stroke, and structural brain lesions. Field management for a brief, self-terminating seizure focuses on protecting the patient from injury and airway compromise during the event, not stopping a seizure that has already stopped."},{"title":"The Postictal State","content":"The postictal state is a period of transient confusion, drowsiness, and sometimes agitation that follows a seizure, typically resolving gradually over minutes without specific intervention. It is a normal, expected part of the seizure process, not a separate emergency — but a patient who does not gradually improve, or whose mental status worsens rather than clears, should prompt reconsideration of other causes (ongoing subclinical seizure activity, structural injury, or a coexisting problem like hypoglycemia)."},{"title":"Status Epilepticus","content":"Status epilepticus — a seizure lasting 5 minutes or longer, or repeated seizures without return to baseline between them — is a time-critical emergency distinct from an ordinary brief seizure. It carries real risk of ongoing neuronal injury and cardiorespiratory compromise the longer it continues. Field priorities are airway protection/positioning, oxygen, glucose check, and rapid transport; benzodiazepine administration for status epilepticus follows local ALS protocol."},{"title":"AEIOU-TIPS: A Framework for Altered Mental Status","content":"AEIOU-TIPS is a widely taught mnemonic for reversible causes of altered mental status: Alcohol, Epilepsy/seizure (postictal), Insulin (hypo/hyperglycemia), Overdose/opioids, Uremia (metabolic), Trauma/temperature, Infection, Psychiatric, Stroke/shock. Its main clinical value is prompting a glucose check and a search for a reversible cause before assuming an irreversible or purely psychiatric explanation for a change in mental status."},{"title":"Field Priorities","content":"For an actively seizing patient: protect the airway with positioning and suction as needed (never place anything in the mouth), protect from injury, time the seizure, and check glucose as soon as feasible. For a newly altered but non-seizing patient: check glucose immediately, work through reversible causes, and gather a focused history (medications, known seizure disorder, substance use, recent illness or head injury) from bystanders or family. Any seizure activity lasting 5 minutes or longer, or that does not resolve with usual measures, should prompt escalation as status epilepticus per local protocol."}],"clinicalPearls":["A brief seizure that has already stopped by EMS arrival does not need seizure-stopping medication — protect and reassess.","The postictal state should gradually improve — if it doesn't, look for another cause.","5 minutes is the threshold for status epilepticus — treat it as a time-critical emergency.","Check glucose in every altered or postictal patient — it's fast, safe, and can immediately explain the presentation."],"redFlags":["Seizure activity lasting 5 minutes or longer, or repeated seizures without return to baseline (status epilepticus).","Postictal confusion that worsens instead of gradually improving.","New focal neurologic deficit after a seizure that doesn't resolve as the postictal state clears (consider Todd's paralysis vs. stroke, but don't assume)."],"commonMistakes":["Placing an object in the mouth of a seizing patient.","Assuming all confusion after a seizure is 'just postictal' without checking glucose.","Waiting well past 5 minutes of continuous seizure activity before escalating care."],"memoryAids":["AEIOU-TIPS: reversible causes of altered mental status.","5 minutes = status epilepticus.","Postictal should get better, not worse — a worsening trend means look further.","Protect, don't restrain, don't put anything in the mouth."],"decisionTrees":[{"title":"Seizure and Altered Mental Status Field Approach","content":"Seizure activity or altered mental status noted\n  → If actively seizing: protect airway/position, protect from injury, time the seizure, check glucose\n     <5 minutes, self-terminates → postictal care, monitor for gradual improvement, transport\n     ≥5 minutes or repeated without return to baseline → Status epilepticus → time-critical emergency, escalate per local ALS protocol, rapid transport\n  → If altered but not seizing: check glucose immediately, treat hypoglycemia if present\n     Work through AEIOU-TIPS for reversible causes; gather focused history from bystanders/family\n  → Reassess mental status trend — gradual improvement is reassuring, no improvement or worsening warrants continued investigation and rapid transport"}],"references":["General EMS/paramedic teaching on seizure classification and status epilepticus (5-minute threshold widely adopted in current EMS education)","AEIOU-TIPS mnemonic — standard EMS teaching framework for altered mental status"]},"c03":{"id":"c03","title":"Endocrine Emergencies — Hypoglycemia, DKA & HHS","shortTitle":"Hypoglycemia, DKA & HHS","estimatedStudyTime":35,"difficulty":"Advanced","learningObjectives":["Recognize the field presentation of hypoglycemia and describe its treatment.","Describe the diagnostic framework for diabetic ketoacidosis (DKA).","Describe the diagnostic framework for hyperosmolar hyperglycemic state (HHS).","Differentiate DKA from HHS on field-relevant grounds.","Explain euglycemic DKA and why a normal glucose does not rule out DKA."],"summary":[{"title":"Hypoglycemia — Fast to Recognize, Fast to Fix","content":"Hypoglycemia presents with a spectrum from mild symptoms (shakiness, diaphoresis, hunger, anxiety) to severe presentations (confusion, combativeness, seizure, unresponsiveness) as glucose falls further. It is common, rapidly correctable, and a well-known mimic of stroke, seizure, and behavioral emergencies — which is why a glucose check is a near-universal first step for any altered patient. Field treatment is oral glucose in an awake, cooperative patient with intact airway reflexes, or IV dextrose / IM glucagon per protocol for a patient who cannot safely take oral glucose."},{"title":"Diabetic Ketoacidosis (DKA)","content":"DKA is a hyperglycemic emergency defined by three features together: hyperglycemia (glucose ≥200 mg/dL, or a prior history of diabetes even without meeting this threshold), ketosis (elevated ketones — beta-hydroxybutyrate ≥3.0 mmol/L or urine ketones 2+ or greater), and metabolic acidosis (pH <7.3 and/or bicarbonate <18 mEq/L). Classic field findings include polyuria/polydipsia leading up to the event, nausea/vomiting, abdominal pain, deep rapid (Kussmaul) respirations as a compensatory response to the acidosis, a fruity (acetone) breath odor, and dehydration. DKA is most classically associated with type 1 diabetes but can occur in type 2 diabetes as well, often precipitated by infection, missed insulin doses, or new-onset diabetes."},{"title":"Euglycemic DKA","content":"Approximately 10% of DKA presentations occur with a glucose under 200 mg/dL — euglycemic DKA — most classically associated with SGLT2-inhibitor diabetes medications, but also seen with reduced oral intake, pregnancy, or partial insulin treatment before presentation. This means a normal or only mildly elevated glucose does not rule out DKA if the clinical picture otherwise fits (Kussmaul respirations, fruity breath, vomiting/abdominal pain, known diabetes) — glucose alone is an incomplete screening tool for this condition."},{"title":"Hyperosmolar Hyperglycemic State (HHS)","content":"HHS is a hyperglycemic emergency defined by severe hyperglycemia (often glucose >600 mg/dL), significant hyperosmolality (>320 mOsm/kg), minimal or absent ketosis, and near-normal pH/bicarbonate — distinguishing it from DKA's acidosis-driven picture. HHS is more typically seen in older adults with type 2 diabetes, often with a slower onset over days, profound dehydration, and a more prominent altered-mental-status/obtundation picture than DKA, reflecting the severe hyperosmolar state's direct effect on the brain. Some patients present with mixed features of both DKA and HHS."},{"title":"Field Management","content":"For both DKA and HHS: supportive care (oxygen as needed, IV access and isotonic fluids per protocol, cardiac monitoring), careful attention to mental status and airway protection given the risk of vomiting, and rapid transport — definitive treatment (insulin, careful fluid/electrolyte correction) happens in the hospital. Field providers should always check glucose in any patient with altered mental status, vomiting, abdominal pain, or unexplained rapid breathing, since DKA/HHS can mimic other conditions and the reverse is also true (do not assume every diabetic patient with altered mental status is hypoglycemic without checking)."}],"clinicalPearls":["Hypoglycemia is common, fast, and correctable — check glucose early in any altered patient.","DKA = hyperglycemia (or known diabetes) + ketosis + acidosis, together — not any one feature alone.","About 10% of DKA is euglycemic (glucose <200 mg/dL) — don't rule out DKA on a normal glucose alone if the clinical picture fits.","HHS = severe hyperglycemia + hyperosmolality + minimal ketosis + near-normal pH — a different mechanism than DKA's acidosis."],"redFlags":["Kussmaul respirations, fruity breath odor, vomiting/abdominal pain in a known or new diabetic patient — think DKA even with a near-normal glucose.","Profound dehydration with severe altered mental status/obtundation in an older type 2 diabetic — think HHS.","Any diabetic patient with altered mental status — check glucose rather than assuming the direction of the abnormality."],"commonMistakes":["Ruling out DKA because the glucose is 'not that high,' without considering euglycemic DKA.","Assuming every altered diabetic patient is hypoglycemic without checking glucose.","Treating DKA/HHS field management as identical to a simple hypoglycemia treat-and-reassess — both need IV fluids and rapid transport, not just glucose correction."],"memoryAids":["DKA: hyperglycemia + ketosis + acidosis, all together.","Kussmaul + fruity breath = think DKA.","HHS: sky-high glucose, sky-high osmolality, minimal ketones.","10% of DKA hides behind a normal-ish glucose — euglycemic DKA is real."],"decisionTrees":[{"title":"Suspected Diabetic Emergency Field Approach","content":"Altered mental status, vomiting, abdominal pain, or unexplained rapid breathing in a known or possible diabetic\n  → Check blood glucose immediately\n  → Low glucose → treat hypoglycemia per protocol (oral glucose if awake/cooperative; IV dextrose or IM glucagon per protocol if not) → reassess\n  → High or near-normal glucose with Kussmaul respirations, fruity breath, vomiting/abdominal pain, dehydration → suspect DKA (consider euglycemic DKA even if glucose is only mildly elevated) → supportive care, IV fluids per protocol, rapid transport\n  → Very high glucose with severe dehydration, minimal respiratory compensation, and profound altered mental status in an older type 2 diabetic → suspect HHS → supportive care, IV fluids per protocol, rapid transport\n  → All suspected DKA/HHS: monitor airway closely given vomiting risk, transport for definitive hospital treatment"}],"references":["ADA Standards of Care in Diabetes—2026, Section 16 (Diabetes Care in the Hospital)","2024 ADA Consensus Report: Hyperglycemic Crises in Adults With Diabetes"]}},"flashcards":{"c01":{"chapter":"c01","cards":[{"id":"c01_fc01","question":"What is a TIA?","answer":"A transient ischemic attack — stroke-like neurologic deficit that resolves completely, classically within minutes to an hour, without lasting tissue injury.","category":"Stroke"},{"id":"c01_fc02","question":"Why is a TIA treated with the same urgency as a stroke in the field?","answer":"It cannot be reliably distinguished from an evolving stroke in the field, and it carries a significant short-term risk of a subsequent completed stroke.","category":"Stroke"},{"id":"c01_fc03","question":"What are the two broad categories of stroke?","answer":"Ischemic (clot/obstruction blocking blood flow) and hemorrhagic (bleeding into or around brain tissue).","category":"Stroke"},{"id":"c01_fc04","question":"Can ischemic and hemorrhagic stroke be reliably distinguished by field symptoms alone?","answer":"No — both cause focal neurologic deficits; the distinction is made by hospital imaging.","category":"Stroke"},{"id":"c01_fc05","question":"What three findings does the Cincinnati Prehospital Stroke Scale (CPSS) check?","answer":"Facial droop, arm drift, and speech abnormality.","category":"Stroke Scales"},{"id":"c01_fc06","question":"Name two prehospital stroke scales beyond CPSS that add sensitivity for detecting large-vessel occlusion (LVO).","answer":"LAPSS (Los Angeles Prehospital Stroke Screen) and RACE (Rapid Arterial oCclusion Evaluation); FAST-ED is another example.","category":"Stroke Scales"},{"id":"c01_fc07","question":"What does FAST-ED add to the standard FAST components?","answer":"Eye deviation and denial/neglect.","category":"Stroke Scales"},{"id":"c01_fc08","question":"What findings raise suspicion for a large-vessel occlusion (LVO) stroke?","answer":"Gaze deviation toward one side, severe unilateral weakness affecting both face and arm together, and neglect/denial of the deficit.","category":"Stroke"},{"id":"c01_fc09","question":"Why might an LVO-screening scale change the destination decision?","answer":"In systems with an endovascular-capable stroke center, a positive LVO screen may justify bypassing a closer, non-endovascular-capable hospital, per local protocol.","category":"Stroke"},{"id":"c01_fc10","question":"Why is checking blood glucose a field priority in suspected stroke?","answer":"Hypoglycemia is a well-known, rapidly correctable stroke mimic.","category":"Field Management"},{"id":"c01_fc11","question":"Why is the last-known-well time so important to document precisely?","answer":"It drives eligibility for time-sensitive hospital treatments.","category":"Field Management"},{"id":"c01_fc12","question":"What is a 'stroke alert'?","answer":"Early hospital notification of a suspected stroke patient so the receiving facility can prepare.","category":"Field Management"},{"id":"c01_fc13","question":"Should transport be delayed to complete an extensive neurologic exam in suspected stroke?","answer":"No — use a rapid validated screening scale and prioritize rapid transport; time is the central variable in stroke outcome.","category":"Field Management"},{"id":"c01_fc14","question":"What is the 2026 guideline governing stroke management referenced in this course?","answer":"The 2026 AHA/ASA Guideline for the Early Management of Patients With Acute Ischemic Stroke.","category":"Guidelines"}]},"c02":{"chapter":"c02","cards":[{"id":"c02_fc01","question":"Are most adult seizures life-threatening?","answer":"No — most are brief, self-limited events that stop on their own within a couple of minutes.","category":"Seizures"},{"id":"c02_fc02","question":"List common causes of adult seizures.","answer":"Idiopathic epilepsy (often with medication non-compliance), hypoglycemia, head trauma, intoxication/withdrawal (especially alcohol withdrawal), fever/infection, stroke, structural brain lesions.","category":"Seizures"},{"id":"c02_fc03","question":"What is the postictal state?","answer":"A period of transient confusion, drowsiness, and sometimes agitation following a seizure, typically resolving gradually over minutes without specific intervention.","category":"Seizures"},{"id":"c02_fc04","question":"Is the postictal state itself an emergency?","answer":"No — it's a normal, expected part of the seizure process, but should gradually improve.","category":"Seizures"},{"id":"c02_fc05","question":"What should worsening (rather than gradually improving) postictal confusion prompt?","answer":"Reconsideration of other causes: ongoing subclinical seizure activity, structural injury, or a coexisting problem like hypoglycemia.","category":"Seizures"},{"id":"c02_fc06","question":"What defines status epilepticus?","answer":"A seizure lasting 5 minutes or longer, or repeated seizures without return to baseline between them.","category":"Seizures"},{"id":"c02_fc07","question":"Is status epilepticus a time-critical emergency?","answer":"Yes — it carries real risk of ongoing neuronal injury and cardiorespiratory compromise the longer it continues.","category":"Seizures"},{"id":"c02_fc08","question":"What are the field priorities for an actively seizing patient?","answer":"Protect the airway (positioning, suction as needed, nothing in the mouth), protect from injury, time the seizure, check glucose as feasible.","category":"Field Management"},{"id":"c02_fc09","question":"What does AEIOU-TIPS help a provider recall?","answer":"Reversible causes of altered mental status: Alcohol, Epilepsy/postictal, Insulin (hypo/hyperglycemia), Overdose, Uremia/metabolic, Trauma/temperature, Infection, Psychiatric, Stroke/shock.","category":"AMS"},{"id":"c02_fc10","question":"What is the main clinical value of the AEIOU-TIPS framework?","answer":"Prompting a glucose check and a search for a reversible cause before assuming an irreversible or purely psychiatric explanation.","category":"AMS"},{"id":"c02_fc11","question":"What should be checked immediately in a newly altered, non-seizing patient?","answer":"Blood glucose.","category":"AMS"},{"id":"c02_fc12","question":"What history elements are useful to gather from bystanders/family for an altered patient?","answer":"Medications, known seizure disorder, substance use, recent illness or head injury.","category":"AMS"},{"id":"c02_fc13","question":"Should something be placed in the mouth of a seizing patient?","answer":"No — never place anything in the mouth during a seizure.","category":"Field Management"},{"id":"c02_fc14","question":"What is the field priority once seizure activity is identified as status epilepticus?","answer":"Escalate per local ALS protocol with rapid transport; benzodiazepine administration follows local protocol.","category":"Field Management"}]},"c03":{"chapter":"c03","cards":[{"id":"c03_fc01","question":"What are early/mild symptoms of hypoglycemia?","answer":"Shakiness, diaphoresis, hunger, anxiety.","category":"Hypoglycemia"},{"id":"c03_fc02","question":"What are severe symptoms of hypoglycemia?","answer":"Confusion, combativeness, seizure, unresponsiveness.","category":"Hypoglycemia"},{"id":"c03_fc03","question":"What is the field treatment for hypoglycemia in an awake, cooperative patient?","answer":"Oral glucose.","category":"Hypoglycemia"},{"id":"c03_fc04","question":"What is the field treatment for hypoglycemia in a patient who cannot safely take oral glucose?","answer":"IV dextrose or IM glucagon per protocol.","category":"Hypoglycemia"},{"id":"c03_fc05","question":"What three features together define DKA?","answer":"Hyperglycemia (glucose ≥200 mg/dL or known diabetes), ketosis (beta-hydroxybutyrate ≥3.0 mmol/L or urine ketones ≥2+), and metabolic acidosis (pH <7.3 and/or bicarbonate <18 mEq/L).","category":"DKA"},{"id":"c03_fc06","question":"What are classic field findings of DKA?","answer":"Polyuria/polydipsia, nausea/vomiting, abdominal pain, Kussmaul respirations, fruity (acetone) breath odor, dehydration.","category":"DKA"},{"id":"c03_fc07","question":"What are Kussmaul respirations, and why do they occur in DKA?","answer":"Deep, rapid respirations that occur as a compensatory response to the metabolic acidosis.","category":"DKA"},{"id":"c03_fc08","question":"What common precipitants trigger DKA?","answer":"Infection, missed insulin doses, or new-onset diabetes.","category":"DKA"},{"id":"c03_fc09","question":"What is euglycemic DKA?","answer":"DKA presenting with a glucose under 200 mg/dL — occurs in about 10% of DKA cases.","category":"DKA"},{"id":"c03_fc10","question":"What medication class is most classically associated with euglycemic DKA?","answer":"SGLT2 inhibitors.","category":"DKA"},{"id":"c03_fc11","question":"Does a normal glucose rule out DKA?","answer":"No — if the clinical picture fits (Kussmaul respirations, fruity breath, vomiting/abdominal pain, known diabetes), DKA should still be suspected.","category":"DKA"},{"id":"c03_fc12","question":"What four features together define HHS?","answer":"Severe hyperglycemia (often >600 mg/dL), significant hyperosmolality (>320 mOsm/kg), minimal or absent ketosis, and near-normal pH/bicarbonate.","category":"HHS"},{"id":"c03_fc13","question":"How does HHS's typical patient and onset differ from DKA's?","answer":"HHS is more typical in older adults with type 2 diabetes, with a slower onset over days, profound dehydration, and more prominent altered mental status/obtundation than DKA.","category":"HHS"},{"id":"c03_fc14","question":"What is the field management priority for both DKA and HHS?","answer":"Supportive care (oxygen as needed, IV access and isotonic fluids per protocol, cardiac monitoring), airway protection given vomiting risk, and rapid transport — definitive treatment happens in the hospital.","category":"Field Management"}]}},"quizzes":{"c01":{"chapter":"c01","questions":[{"id":"c01_q01","question":"What defines a TIA (transient ischemic attack)?","options":["A. A stroke that leaves permanent deficits","B. Stroke-like neurologic deficit that resolves completely, classically within minutes to an hour","C. A minor headache with no neurologic findings","D. A seizure followed by confusion"],"correct":1,"rationale":"A TIA produces stroke-like focal neurologic deficit that resolves completely without lasting tissue injury, classically within minutes to an hour.","difficulty":"Easy"},{"id":"c01_q02","question":"Why is a TIA treated with the same field urgency as an ongoing stroke?","options":["A. It cannot be reliably distinguished from an evolving stroke in the field, and carries short-term risk of a completed stroke","B. TIAs are more dangerous than strokes","C. TIA is simply an outdated term for stroke","D. There is no urgency difference because TIAs are never serious"],"correct":0,"rationale":"Because a TIA can't be reliably distinguished from an evolving stroke in the field, and TIA patients face a meaningful short-term risk of a subsequent completed stroke, both are managed with the same urgency.","difficulty":"Medium"},{"id":"c01_q03","question":"What are the two broad categories of stroke?","options":["A. Ischemic and hemorrhagic","B. Acute and chronic","C. Central and peripheral","D. Primary and secondary"],"correct":0,"rationale":"Stroke is broadly categorized as ischemic (obstruction of blood flow) or hemorrhagic (bleeding into/around brain tissue).","difficulty":"Easy"},{"id":"c01_q04","question":"Can ischemic and hemorrhagic stroke be reliably distinguished in the field by symptoms alone?","options":["A. Yes, symptoms are always distinct","B. No — both cause focal neurologic deficits; imaging is needed to distinguish them","C. Only hemorrhagic stroke causes a facial droop","D. Only ischemic stroke causes speech abnormality"],"correct":1,"rationale":"Field symptoms cannot reliably distinguish the two stroke types; both produce focal neurologic deficits, and hospital imaging is required to differentiate them.","difficulty":"Medium"},{"id":"c01_q05","question":"What three findings does the Cincinnati Prehospital Stroke Scale (CPSS) assess?","options":["A. Facial droop, arm drift, speech abnormality","B. Blood pressure, heart rate, respiratory rate","C. Pupil size, gag reflex, grip strength","D. Gaze deviation, neglect, ataxia"],"correct":0,"rationale":"CPSS checks facial droop, arm drift, and speech abnormality as its three core findings.","difficulty":"Easy"},{"id":"c01_q06","question":"What is the purpose of an LVO-screening scale like RACE or FAST-ED?","options":["A. To diagnose the exact stroke type in the field","B. To add sensitivity for detecting a large-vessel occlusion, which may inform destination decisions","C. To replace blood glucose checks","D. To determine the patient's code status"],"correct":1,"rationale":"LVO-screening scales add sensitivity for detecting large-vessel occlusion strokes, which may influence a destination decision toward an endovascular-capable center per local protocol.","difficulty":"Medium"},{"id":"c01_q07","question":"What does FAST-ED add to the standard FAST components?","options":["A. Eye deviation and denial/neglect","B. Blood glucose and temperature","C. Pupil reactivity","D. Grip strength bilaterally"],"correct":0,"rationale":"FAST-ED extends FAST by adding eye (gaze) deviation and denial/neglect to improve LVO detection sensitivity.","difficulty":"Medium"},{"id":"c01_q08","question":"Which findings raise suspicion for a large-vessel occlusion (LVO) stroke?","options":["A. Isolated mild facial droop only","B. Gaze deviation, severe combined face+arm weakness, and neglect of the deficit","C. A resolved speech abnormality with normal exam otherwise","D. Isolated numbness without weakness"],"correct":1,"rationale":"Gaze deviation, severe unilateral face+arm weakness together, and neglect/denial of the deficit are findings that raise LVO suspicion beyond a basic FAST-positive screen.","difficulty":"Hard"},{"id":"c01_q09","question":"Why should blood glucose be checked in a suspected stroke patient?","options":["A. Hypoglycemia is a well-known, rapidly correctable stroke mimic","B. Glucose has no relevance to neurologic presentations","C. It replaces the need for a stroke scale","D. It is only relevant in diabetic patients"],"correct":0,"rationale":"Hypoglycemia can mimic a focal neurologic deficit and is rapidly correctable, making a glucose check a high-value field step in suspected stroke.","difficulty":"Medium"},{"id":"c01_q10","question":"Why is documenting the last-known-well time so important?","options":["A. It drives eligibility for time-sensitive hospital treatments","B. It is only used for billing purposes","C. It has no bearing on hospital treatment decisions","D. It replaces the need for a stroke scale"],"correct":0,"rationale":"Last-known-well time is a key driver of eligibility for time-sensitive interventions at the receiving hospital, making precise documentation a high priority.","difficulty":"Medium"},{"id":"c01_q11","question":"What is a 'stroke alert'?","options":["A. A patient-initiated emergency call","B. Early hospital notification of a suspected stroke patient so the receiving facility can prepare","C. A specific stroke medication","D. A type of cardiac monitor alarm"],"correct":1,"rationale":"A stroke alert is early notification to the receiving hospital, allowing the stroke team to prepare before patient arrival.","difficulty":"Easy"},{"id":"c01_q12","question":"Should transport be delayed to perform a full, extensive neurologic exam on a suspected stroke patient?","options":["A. Yes, always complete a full exam before transport","B. No — use a rapid validated screening scale and prioritize rapid transport, since time is central to stroke outcome","C. Only if the patient requests it","D. Only for hemorrhagic strokes"],"correct":1,"rationale":"Time is the central variable in stroke outcomes, so field care uses a rapid screening scale rather than delaying transport for an extensive exam.","difficulty":"Medium"},{"id":"c01_q13","question":"A patient had left-sided facial droop and slurred speech that fully resolved 20 minutes before EMS arrival. How should this be treated?","options":["A. As a non-urgent complaint since symptoms resolved","B. With the same urgency as an active stroke, given the possibility of TIA and risk of a subsequent stroke","C. Only urgent if the patient becomes symptomatic again","D. As a psychiatric complaint given full resolution"],"correct":1,"rationale":"A resolved deficit consistent with TIA still carries meaningful short-term stroke risk and should be treated with full stroke-protocol urgency.","difficulty":"Hard"},{"id":"c01_q14","question":"A stroke patient has gaze deviation to the right, severe right face and arm weakness, and does not acknowledge the weak arm. What should this presentation raise suspicion for?","options":["A. A simple TIA with no further workup needed","B. Possible large-vessel occlusion (LVO) stroke, potentially warranting an LVO-screening-based destination decision","C. A hypoglycemic event with no stroke involvement","D. A behavioral/psychiatric emergency"],"correct":1,"rationale":"Gaze deviation, combined severe face+arm weakness, and neglect of the deficit are classic LVO-suspicious findings that may change the transport destination decision per local protocol.","difficulty":"Hard"},{"id":"c01_q15","question":"Which guideline is the authoritative current source for stroke management referenced in this course?","options":["A. The 2026 AHA/ASA Guideline for the Early Management of Patients With Acute Ischemic Stroke","B. GINA 2025","C. DSM-5-TR","D. ADA Standards of Care 2026"],"correct":0,"rationale":"The 2026 AHA/ASA Guideline for the Early Management of Patients With Acute Ischemic Stroke is the current authoritative source, replacing the 2018/2019 guideline.","difficulty":"Easy"}]},"c02":{"chapter":"c02","questions":[{"id":"c02_q01","question":"Are most adult seizures life-threatening events requiring aggressive intervention?","options":["A. Yes, all seizures require immediate medication","B. No — most are brief, self-limited, and stop on their own","C. Only seizures in elderly patients are self-limited","D. Seizures are always a sign of stroke"],"correct":1,"rationale":"Most adult seizures are brief and self-terminating; field management for these focuses on protection, not stopping an already-resolved seizure.","difficulty":"Easy"},{"id":"c02_q02","question":"Which of the following is a common cause of adult seizures?","options":["A. Hypoglycemia","B. Normal blood pressure","C. Adequate sleep","D. Mild dehydration alone"],"correct":0,"rationale":"Hypoglycemia is a common and important cause of adult seizures, alongside epilepsy, head trauma, intoxication/withdrawal, infection, and stroke.","difficulty":"Easy"},{"id":"c02_q03","question":"What is the postictal state?","options":["A. A period of transient confusion/drowsiness following a seizure that typically resolves gradually","B. The seizure itself","C. A permanent neurologic deficit","D. A medication used to stop seizures"],"correct":0,"rationale":"The postictal state is a transient period of confusion or drowsiness after a seizure that generally resolves gradually without specific intervention.","difficulty":"Easy"},{"id":"c02_q04","question":"What should worsening postictal confusion (rather than gradual improvement) prompt?","options":["A. No action, since postictal confusion is always benign","B. Reconsideration of other causes: ongoing subclinical seizure, structural injury, or hypoglycemia","C. Immediate discharge from care","D. Assumption that the patient is malingering"],"correct":1,"rationale":"The postictal state should improve gradually; worsening confusion should prompt investigation of alternative or coexisting causes.","difficulty":"Medium"},{"id":"c02_q05","question":"What defines status epilepticus?","options":["A. Any seizure lasting more than 30 seconds","B. A seizure lasting 5 minutes or longer, or repeated seizures without return to baseline","C. Only seizures caused by epilepsy","D. A seizure that occurs during sleep"],"correct":1,"rationale":"Status epilepticus is defined as a seizure lasting 5 minutes or more, or repeated seizures without return to baseline between them.","difficulty":"Medium"},{"id":"c02_q06","question":"Why is status epilepticus considered a time-critical emergency?","options":["A. It carries risk of ongoing neuronal injury and cardiorespiratory compromise the longer it continues","B. It has no clinical significance beyond a brief seizure","C. It only affects patients with a prior seizure history","D. It resolves faster than a brief seizure"],"correct":0,"rationale":"The longer status epilepticus continues, the greater the risk of neuronal injury and cardiorespiratory compromise, making rapid recognition and escalation important.","difficulty":"Medium"},{"id":"c02_q07","question":"What are the correct field priorities for an actively seizing patient?","options":["A. Place a bite block in the mouth and restrain the limbs","B. Protect the airway/position, protect from injury, time the seizure, check glucose","C. Administer oral medication immediately","D. Perform chest compressions"],"correct":1,"rationale":"Correct seizure management is airway protection/positioning, injury protection, timing the seizure, and checking glucose — never placing objects in the mouth or restraining limbs.","difficulty":"Easy"},{"id":"c02_q08","question":"What does the AEIOU-TIPS mnemonic help a provider recall?","options":["A. Steps of CPR","B. Reversible causes of altered mental status","C. Categories of shock","D. Stroke scale components"],"correct":1,"rationale":"AEIOU-TIPS recalls reversible causes of altered mental status: Alcohol, Epilepsy, Insulin, Overdose, Uremia, Trauma/temperature, Infection, Psychiatric, Stroke/shock.","difficulty":"Medium"},{"id":"c02_q09","question":"What is the main clinical value of the AEIOU-TIPS framework?","options":["A. It replaces the need for any physical exam","B. It prompts a glucose check and search for a reversible cause before assuming an irreversible explanation","C. It is used only for pediatric patients","D. It is a stroke scale"],"correct":1,"rationale":"AEIOU-TIPS is valuable primarily because it prompts systematic consideration of reversible causes, starting with glucose, before assuming a fixed or purely psychiatric cause.","difficulty":"Medium"},{"id":"c02_q10","question":"What should be checked immediately in a newly altered, non-seizing adult patient?","options":["A. Blood glucose","B. Blood type","C. Recent dental history","D. Vaccination status"],"correct":0,"rationale":"Blood glucose is a fast, safe, high-value check that can immediately explain (and treat) altered mental status.","difficulty":"Easy"},{"id":"c02_q11","question":"Should an object be placed in the mouth of a seizing patient to prevent tongue-biting?","options":["A. Yes, always use a bite block","B. No — never place anything in the mouth during a seizure","C. Only for pediatric patients","D. Only if the patient requests it"],"correct":1,"rationale":"Placing objects in the mouth during a seizure is unnecessary and can cause injury; this is a common and important mistake to avoid.","difficulty":"Easy"},{"id":"c02_q12","question":"A patient seized for 2 minutes and stopped before EMS arrival, now in a gradually clearing postictal state. What is the appropriate management?","options":["A. Administer a benzodiazepine to stop the ongoing seizure","B. Protect and monitor, check glucose, and transport — no seizure-stopping medication is needed since the seizure has already resolved","C. Perform immediate advanced airway placement","D. Restrain the patient to prevent further seizure activity"],"correct":1,"rationale":"A brief seizure that has already terminated does not require abortive medication; management is supportive with glucose check and monitoring for gradual improvement.","difficulty":"Medium"},{"id":"c02_q13","question":"A patient has been continuously seizing for 7 minutes. What should this be treated as?","options":["A. A normal, self-limited seizure requiring no escalation","B. Status epilepticus — a time-critical emergency requiring escalation per local ALS protocol","C. A postictal state","D. A psychiatric emergency"],"correct":1,"rationale":"Seizure activity exceeding the 5-minute threshold is status epilepticus, requiring escalation and rapid transport.","difficulty":"Medium"},{"id":"c02_q14","question":"A patient remains altered and confused 45 minutes after an observed seizure, with no improvement. What should this prompt?","options":["A. Assumption this is normal, prolonged postictal state requiring no further evaluation","B. Investigation of other causes since postictal confusion should gradually improve, not persist unchanged","C. Immediate discharge since seizures are self-limited","D. Assumption the patient is intentionally faking symptoms"],"correct":1,"rationale":"Persistent, non-improving altered mental status well beyond the expected postictal window should prompt investigation for another or coexisting cause (e.g., ongoing subclinical seizure, structural injury, hypoglycemia).","difficulty":"Hard"},{"id":"c02_q15","question":"Why is a focused history from bystanders/family (medications, seizure history, substance use, recent illness/injury) valuable in an altered patient?","options":["A. It has no clinical value in the field","B. It can point toward a specific reversible cause and guide field management priorities","C. It replaces the need for a glucose check","D. It is only relevant for pediatric patients"],"correct":1,"rationale":"A focused collateral history can quickly point toward a likely cause (e.g., known epilepsy with medication non-compliance, or a substance use history), guiding field priorities alongside the AEIOU-TIPS framework.","difficulty":"Medium"}]},"c03":{"chapter":"c03","questions":[{"id":"c03_q01","question":"What are early/mild symptoms of hypoglycemia?","options":["A. Shakiness, diaphoresis, hunger, anxiety","B. Fever and rash","C. Chest pain and dyspnea","D. Joint pain and swelling"],"correct":0,"rationale":"Mild hypoglycemia classically presents with shakiness, diaphoresis, hunger, and anxiety before progressing to more severe neurologic symptoms.","difficulty":"Easy"},{"id":"c03_q02","question":"What is the field treatment for hypoglycemia in an awake, cooperative patient with intact airway reflexes?","options":["A. IM glucagon only","B. Oral glucose","C. Withhold treatment until hospital arrival","D. IV insulin"],"correct":1,"rationale":"Oral glucose is appropriate for an awake, cooperative patient who can safely swallow.","difficulty":"Easy"},{"id":"c03_q03","question":"What three features together define DKA?","options":["A. Hyperglycemia, ketosis, and metabolic acidosis","B. Hypoglycemia, ketosis, and alkalosis","C. Hyperglycemia alone","D. Fever, tachycardia, and hypertension"],"correct":0,"rationale":"DKA requires all three: hyperglycemia (or known diabetes), ketosis, and metabolic acidosis together.","difficulty":"Medium"},{"id":"c03_q04","question":"What glucose threshold is generally used to define hyperglycemia in DKA (absent a prior diabetes diagnosis)?","options":["A. ≥100 mg/dL","B. ≥140 mg/dL","C. ≥200 mg/dL","D. ≥600 mg/dL"],"correct":2,"rationale":"The DKA hyperglycemia criterion is glucose ≥200 mg/dL, or a prior history of diabetes even without meeting this threshold.","difficulty":"Medium"},{"id":"c03_q05","question":"What are Kussmaul respirations, and why do they occur in DKA?","options":["A. Shallow, slow breathing from CNS depression","B. Deep, rapid respirations as a compensatory response to metabolic acidosis","C. Irregular gasping unrelated to acid-base status","D. Normal breathing pattern with no clinical significance"],"correct":1,"rationale":"Kussmaul respirations are deep, rapid breaths that compensate for metabolic acidosis by blowing off CO2.","difficulty":"Medium"},{"id":"c03_q06","question":"What breath odor is classically associated with DKA?","options":["A. Ammonia","B. Fruity (acetone)","C. Rotten eggs","D. No characteristic odor"],"correct":1,"rationale":"A fruity, acetone-like breath odor is a classic finding in DKA due to ketone production.","difficulty":"Easy"},{"id":"c03_q07","question":"What percentage of DKA presentations occur with euglycemic DKA (glucose <200 mg/dL)?","options":["A. About 1%","B. About 10%","C. About 50%","D. About 90%"],"correct":1,"rationale":"Approximately 10% of DKA presentations are euglycemic, with glucose under 200 mg/dL.","difficulty":"Medium"},{"id":"c03_q08","question":"What medication class is most classically associated with euglycemic DKA?","options":["A. SGLT2 inhibitors","B. Beta-blockers","C. ACE inhibitors","D. Statins"],"correct":0,"rationale":"SGLT2-inhibitor diabetes medications are the classic association with euglycemic DKA.","difficulty":"Hard"},{"id":"c03_q09","question":"Does a normal or only mildly elevated glucose rule out DKA?","options":["A. Yes, DKA cannot occur without a very high glucose","B. No — if the clinical picture fits (Kussmaul respirations, fruity breath, vomiting/abdominal pain), DKA should still be suspected","C. Yes, but only in type 1 diabetics","D. Glucose has no relationship to DKA diagnosis"],"correct":1,"rationale":"Because of euglycemic DKA, a normal or mildly elevated glucose does not rule out DKA if other clinical features are present.","difficulty":"Hard"},{"id":"c03_q10","question":"What four features together define HHS?","options":["A. Severe hyperglycemia, significant hyperosmolality, minimal ketosis, near-normal pH/bicarbonate","B. Hypoglycemia, ketosis, acidosis, hypotension","C. Fever, tachycardia, hyperglycemia, ketosis","D. Normal glucose, high ketones, severe acidosis"],"correct":0,"rationale":"HHS is defined by severe hyperglycemia (often >600 mg/dL), hyperosmolality (>320 mOsm/kg), minimal ketosis, and near-normal pH/bicarbonate — distinguishing it from DKA's acidosis picture.","difficulty":"Medium"},{"id":"c03_q11","question":"Which patient population is HHS more typically seen in?","options":["A. Younger patients with type 1 diabetes and rapid onset","B. Older adults with type 2 diabetes and slower onset over days","C. Children with new-onset diabetes","D. HHS occurs equally across all diabetic populations and onset patterns"],"correct":1,"rationale":"HHS is more typical in older adults with type 2 diabetes, with a slower onset over days and profound dehydration.","difficulty":"Medium"},{"id":"c03_q12","question":"How does the mental status picture in HHS typically compare to DKA?","options":["A. HHS typically has a more prominent altered mental status/obtundation picture than DKA","B. DKA always causes more severe altered mental status than HHS","C. Neither condition affects mental status","D. Mental status changes are identical and cannot be distinguished"],"correct":0,"rationale":"HHS's severe hyperosmolar state has a direct effect on the brain, often producing more prominent altered mental status/obtundation than typical DKA.","difficulty":"Hard"},{"id":"c03_q13","question":"What is the field management priority for both DKA and HHS?","options":["A. Oral glucose administration","B. Supportive care (oxygen, IV access/isotonic fluids per protocol, cardiac monitoring), airway protection, and rapid transport","C. Withholding all fluids until hospital arrival","D. Immediate insulin administration in the field"],"correct":1,"rationale":"Field management for DKA/HHS is supportive — fluids, oxygen, monitoring, airway protection given vomiting risk, and rapid transport; definitive treatment (insulin, careful correction) happens in the hospital.","difficulty":"Medium"},{"id":"c03_q14","question":"A known diabetic patient presents with confusion. Should the provider assume hypoglycemia without checking glucose?","options":["A. Yes, all diabetic confusion is hypoglycemia","B. No — check glucose, since altered mental status could reflect hypoglycemia, DKA, or HHS","C. Yes, but only if the patient is elderly","D. No check is needed if the patient appears calm"],"correct":1,"rationale":"Altered mental status in a diabetic patient could reflect either direction of glucose abnormality (or DKA/HHS); a glucose check is required rather than assuming the direction.","difficulty":"Medium"},{"id":"c03_q15","question":"A type 2 diabetic patient on an SGLT2 inhibitor presents with vomiting, abdominal pain, and Kussmaul respirations, with a glucose of 180 mg/dL. What should this raise suspicion for?","options":["A. This cannot be DKA since the glucose is under 200 mg/dL","B. Euglycemic DKA, given the SGLT2-inhibitor use and fitting clinical picture despite a near-normal glucose","C. Simple gastroenteritis with no endocrine involvement","D. HHS, given the diabetes history"],"correct":1,"rationale":"SGLT2-inhibitor use plus a DKA-consistent clinical picture (vomiting, abdominal pain, Kussmaul respirations) despite a near-normal glucose is the classic presentation of euglycemic DKA.","difficulty":"Hard"}]}},"scenarios":{"c01":{"chapter":"c01","cases":[{"id":"c01_s01","title":"The Resolved Deficit","presentation":"A 68-year-old man had sudden right-sided facial droop and slurred speech about 40 minutes ago while at a family lunch. By the time EMS arrives, his speech is clear and his face appears symmetric. He feels fine and wants to cancel the ambulance.","vitals":{"bp":"148/86 mmHg","hr":"78 bpm","glucose":"98 mg/dL","exam":"Currently normal facial symmetry and speech"},"question":"What is the appropriate approach to this patient?","options":["A: Cancel transport since the exam is now normal.","B: Treat this as a possible TIA with the same urgency as an active stroke, document the last-known-well/onset time precisely, and transport with hospital notification.","C: Advise the patient to see his primary doctor within the week.","D: Transport only if symptoms recur during the encounter."],"correct":1,"explanation":"A resolved facial droop and speech abnormality is classic for a possible TIA, which cannot be reliably distinguished from an evolving stroke in the field and carries meaningful short-term risk of a subsequent completed stroke. This should be treated with the same urgency as an active stroke, with precise onset-time documentation and prompt transport.","clinicalPearl":"A resolved deficit is not a reason to relax — it's a reason to document the timeline precisely and transport with full urgency."},{"id":"c01_s02","title":"Confusion With a Normal Glucose Twist","presentation":"A 74-year-old woman is found by family with new left arm weakness and confusion. Initial impression suggests possible stroke. On scene, her blood glucose reads 42 mg/dL.","vitals":{"bp":"132/78 mmHg","hr":"92 bpm","glucose":"42 mg/dL","exam":"Left arm weakness, confusion"},"question":"What is the correct next step?","options":["A: Proceed directly to stroke-alert transport without addressing the glucose value.","B: Treat the hypoglycemia per protocol first, since it is a well-known, rapidly correctable stroke mimic, and reassess neurologic status afterward.","C: Ignore the glucose reading since the presentation looks like a clear stroke.","D: Withhold treatment until arrival at the hospital."],"correct":1,"explanation":"Hypoglycemia is a well-known stroke mimic that is rapidly correctable in the field. Treating the hypoglycemia and reassessing neurologic status is the correct next step before finalizing the working diagnosis and destination decision — a focal deficit that resolves with glucose correction is not treated as a stroke alert.","clinicalPearl":"Always check glucose before you commit to a stroke diagnosis in the field — a fixable stroke mimic can save this patient a stroke-center transport they don't need."},{"id":"c01_s03","title":"Gaze Deviation and Neglect","presentation":"A 59-year-old man has sudden onset of right gaze deviation, severe left face and arm weakness, and does not acknowledge that his left arm is weak when asked. Local EMS protocol uses an LVO-screening scale to determine bypass eligibility to an endovascular-capable stroke center.","vitals":{"bp":"168/94 mmHg","hr":"88 bpm","glucose":"110 mg/dL","exam":"Gaze deviation, severe left face+arm weakness, neglect of left arm"},"question":"What should this constellation of findings prompt?","options":["A: A routine transport to the nearest hospital regardless of capability.","B: Application of the LVO-screening scale per protocol, since these findings (gaze deviation, combined severe face+arm weakness, neglect) suggest possible large-vessel occlusion, potentially justifying bypass to an endovascular-capable center.","C: Assumption that this cannot be a stroke because the deficit is too severe.","D: Delaying the stroke alert until arrival at the hospital."],"correct":1,"explanation":"Gaze deviation, severe combined face and arm weakness, and neglect of the affected limb are LVO-suspicious findings. Per local protocol using an LVO-screening scale, this presentation may justify bypassing a closer, non-endovascular-capable hospital in favor of an endovascular-capable stroke center.","clinicalPearl":"Gaze deviation plus neglect plus severe combined weakness is the pattern that makes an LVO-screening scale worth applying — it can change where this patient needs to go."}]},"c02":{"chapter":"c02","cases":[{"id":"c02_s01","title":"The Already-Stopped Seizure","presentation":"A 34-year-old man with known epilepsy is found postictal by coworkers after a witnessed generalized seizure that lasted about 90 seconds and has since stopped. He is confused but gradually becoming more oriented over the next few minutes.","vitals":{"glucose":"104 mg/dL","hr":"96 bpm","appearance":"Postictal, gradually clearing"},"question":"What is the correct field management?","options":["A: Administer a benzodiazepine to stop the seizure.","B: Protect and monitor, confirm glucose is normal, and allow the postictal state to clear while transporting.","C: Restrain the patient to prevent another seizure.","D: Delay transport until the patient is fully back to baseline on scene."],"correct":1,"explanation":"This is a brief, self-terminated seizure with a normally clearing postictal state in a patient with known epilepsy — no seizure-stopping medication is needed since the seizure has already resolved. Confirming glucose and monitoring for gradual improvement while transporting is appropriate.","clinicalPearl":"A seizure that's already over doesn't need to be 'stopped' — confirm glucose, protect, and let the postictal state clear en route."},{"id":"c02_s02","title":"Confusion With a Hidden Cause","presentation":"A 52-year-old woman with type 1 diabetes is found confused and diaphoretic by her spouse. There is no witnessed seizure. She is oriented to name only.","vitals":{"glucose":"38 mg/dL","hr":"110 bpm","skin":"Diaphoretic"},"question":"What is the most appropriate first action?","options":["A: Assume a primary psychiatric cause and proceed to a mental health facility.","B: Treat the hypoglycemia per protocol, given the low glucose reading and diaphoresis, then reassess mental status.","C: Perform a full neurologic exam before any treatment.","D: Wait to see if she improves spontaneously without intervention."],"correct":1,"explanation":"Diaphoresis and confusion with a documented glucose of 38 mg/dL point to hypoglycemia as the cause of altered mental status — consistent with the AEIOU-TIPS framework's emphasis on checking and treating glucose early. Treating the hypoglycemia is the priority before further workup.","clinicalPearl":"Diaphoresis plus confusion in a diabetic patient is hypoglycemia until proven otherwise — treat first, then reassess."},{"id":"c02_s03","title":"Six Minutes and Counting","presentation":"A 45-year-old man is having continuous generalized tonic-clonic seizure activity. Bystanders report it began approximately 6 minutes before EMS arrival, and it is still ongoing.","vitals":{"duration":"6+ minutes, ongoing","spo2":"89% during active seizure"},"question":"How should this presentation be classified and managed?","options":["A: A normal seizure requiring only observation.","B: Status epilepticus — a time-critical emergency requiring airway/oxygen support, glucose check, and escalation per local ALS protocol with rapid transport.","C: A postictal state requiring no intervention.","D: A psychiatric event requiring police involvement rather than EMS treatment."],"correct":1,"explanation":"Continuous seizure activity exceeding 5 minutes meets the definition of status epilepticus, a time-critical emergency. Field priorities are airway protection, oxygen, a glucose check, and escalation per local ALS protocol (e.g., benzodiazepine per protocol) with rapid transport.","clinicalPearl":"Once a seizure crosses the 5-minute mark, stop waiting and start escalating — status epilepticus doesn't resolve itself reliably."}]},"c03":{"chapter":"c03","cases":[{"id":"c03_s01","title":"Shaky and Sweaty","presentation":"A 29-year-old woman with type 1 diabetes is found shaky, diaphoretic, and anxious after skipping breakfast before a workout. She is alert and able to swallow safely.","vitals":{"glucose":"52 mg/dL","hr":"104 bpm","appearance":"Alert, diaphoretic, shaky"},"question":"What is the appropriate field treatment?","options":["A: IM glucagon, since she is diabetic.","B: Oral glucose, since she is alert, cooperative, and able to swallow safely.","C: IV dextrose only, bypassing oral options.","D: No treatment needed since symptoms are mild."],"correct":1,"explanation":"This is mild hypoglycemia in an alert patient with intact airway reflexes who can safely swallow — oral glucose is the appropriate first-line treatment rather than IM glucagon or IV dextrose, which are reserved for patients who cannot safely take oral glucose.","clinicalPearl":"If they're awake and can swallow safely, oral glucose is simpler and just as effective as IV or IM routes."},{"id":"c03_s02","title":"Vomiting With a Near-Normal Glucose","presentation":"A 41-year-old man with type 2 diabetes on an SGLT2-inhibitor medication presents with two days of vomiting, abdominal pain, and unusually deep, rapid breathing. His glucose reads 175 mg/dL.","vitals":{"glucose":"175 mg/dL","rr":"28/min, deep pattern","breath":"Fruity odor noted"},"question":"What should this presentation raise suspicion for, despite the near-normal glucose?","options":["A: This cannot be a diabetic emergency since the glucose is not significantly elevated.","B: Euglycemic DKA, given the SGLT2-inhibitor use, Kussmaul-pattern breathing, fruity breath odor, and vomiting/abdominal pain.","C: Simple viral gastroenteritis unrelated to his diabetes.","D: HHS, given his type 2 diabetes history."],"correct":1,"explanation":"SGLT2-inhibitor use combined with Kussmaul respirations, fruity breath odor, and vomiting/abdominal pain is the classic presentation of euglycemic DKA — a normal or near-normal glucose does not rule out DKA in this context, and roughly 10% of DKA presents this way.","clinicalPearl":"SGLT2 inhibitor plus a DKA-looking picture with a normal-ish glucose is the textbook setup for euglycemic DKA — don't let the glucose number reassure you."},{"id":"c03_s03","title":"Days of Decline","presentation":"An 78-year-old woman with type 2 diabetes has become progressively more confused and lethargic over three days, with poor oral intake and profound dry mucous membranes. Her glucose reads 720 mg/dL.","vitals":{"glucose":"720 mg/dL","appearance":"Obtunded, severely dehydrated","rr":"Near-normal pattern"},"question":"What does this presentation most likely represent, and what is the field management priority?","options":["A: DKA — administer field insulin immediately.","B: HHS — provide supportive care (oxygen, IV fluids per protocol, monitoring), protect the airway, and transport rapidly for definitive hospital treatment.","C: Simple hypoglycemia — administer oral glucose.","D: A primary psychiatric condition unrelated to her diabetes."],"correct":1,"explanation":"Severe hyperglycemia, profound dehydration, slower multi-day onset, prominent obtundation, and a near-normal respiratory pattern (rather than Kussmaul) in an older type 2 diabetic patient are classic for HHS rather than DKA. Field management is supportive care and rapid transport — insulin administration is a hospital-level intervention, not a field one.","clinicalPearl":"Slow onset, severe dehydration, profound confusion, and sky-high glucose without Kussmaul breathing points toward HHS, not DKA — support and transport, don't try to fix the glucose in the field."}]}},"algorithms":{"c01":{"chapter":"c01","algorithms":[{"id":"c01_alg01","title":"Suspected Stroke Field Recognition and Transport Decision","description":"Sequence for recognizing suspected stroke, ruling out a correctable mimic, and deciding on transport destination.","steps":["Identify a new focal neurologic deficit (current or recently resolved) using a validated stroke scale (e.g., CPSS: facial droop, arm drift, speech abnormality).","Check blood glucose immediately; treat hypoglycemia per protocol if present and reassess neurologic status.","Determine and precisely document the last-known-well time from the patient/bystanders.","Assess for LVO-suspicious findings (gaze deviation, severe combined face+arm weakness, neglect/denial) using a local LVO-screening scale if available.","Provide early hospital notification ('stroke alert') so the receiving facility can prepare.","Transport per local destination protocol — nearest stroke-capable hospital, or bypass to an endovascular-capable center if LVO screen is positive and system design supports it.","Reassess neurologic status serially en route without delaying transport for an extensive exam."]}]},"c02":{"chapter":"c02","algorithms":[{"id":"c02_alg01","title":"Seizure and Altered Mental Status Field Approach","description":"Sequence for assessing and managing a seizing or newly altered adult patient.","steps":["If actively seizing: protect the airway with positioning and suction as needed (never place anything in the mouth), protect the patient from injury, and time the seizure.","Check blood glucose as soon as feasible; treat hypoglycemia per protocol if present.","If the seizure resolves in under 5 minutes: provide postictal supportive care, monitor for gradual improvement, and transport.","If seizure activity reaches 5 minutes or repeats without return to baseline: treat as status epilepticus — escalate per local ALS protocol (airway/oxygen support, benzodiazepine per protocol) and transport rapidly.","If altered but not seizing: check glucose immediately, then work through AEIOU-TIPS for reversible causes.","Gather a focused history from bystanders/family: medications, known seizure disorder, substance use, recent illness or head injury.","Reassess mental status trend continuously; a lack of gradual improvement warrants continued investigation and prompt transport."]}]},"c03":{"chapter":"c03","algorithms":[{"id":"c03_alg01","title":"Suspected Diabetic Emergency Field Approach","description":"Sequence for evaluating altered mental status, vomiting, abdominal pain, or unexplained rapid breathing in a known or possible diabetic patient.","steps":["Check blood glucose immediately in any altered, vomiting, or unusually tachypneic patient with known or suspected diabetes.","If glucose is low: treat hypoglycemia per protocol (oral glucose if awake/cooperative; IV dextrose or IM glucagon per protocol if not) and reassess.","If glucose is high or only mildly elevated with Kussmaul respirations, fruity breath odor, vomiting/abdominal pain, and dehydration: suspect DKA, including euglycemic DKA if glucose is near-normal.","If glucose is very high with profound dehydration, slower onset, minimal respiratory compensation, and prominent altered mental status/obtundation: suspect HHS.","For suspected DKA or HHS: provide supportive care (oxygen as needed, IV access and isotonic fluids per protocol, cardiac monitoring), protect the airway given vomiting risk.","Transport rapidly for definitive hospital treatment (insulin, careful fluid/electrolyte correction) — do not attempt to correct DKA/HHS glucose with field insulin."]}]}},"tables":{"c01":{"chapter":"c01","tables":[{"id":"c01_t01","title":"Prehospital Stroke Scale Comparison","headers":["Scale","What It Adds","Components Checked","Primary Use"],"rows":[["CPSS (Cincinnati Prehospital Stroke Scale)","Baseline stroke screening","Facial droop, arm drift, speech abnormality","General stroke recognition"],["LAPSS (Los Angeles Prehospital Stroke Screen)","Adds exclusion criteria (age, glucose, symptom duration, prior seizure/wheelchair history)","Facial droop, grip strength, arm drift, plus exclusion criteria","General stroke recognition with mimic screening"],["RACE (Rapid Arterial oCclusion Evaluation)","Adds LVO-sensitive items","Facial palsy, arm motor, leg motor, gaze deviation, aphasia/agnosia","Large-vessel occlusion (LVO) screening"],["FAST-ED","Adds eye deviation and denial/neglect to FAST","Face, Arm, Speech, Time + Eye deviation, Denial/neglect","Large-vessel occlusion (LVO) screening"]]},{"id":"c01_t02","title":"Ischemic vs. Hemorrhagic Stroke — Field Perspective","headers":["Feature","Ischemic Stroke","Hemorrhagic Stroke"],"rows":[["Mechanism","Obstruction (clot) blocking blood flow","Bleeding into or around brain tissue"],["Relative frequency","Majority of strokes","Minority of strokes"],["Field distinguishability by symptoms","Not reliably distinguishable from hemorrhagic by symptoms alone","Not reliably distinguishable from ischemic by symptoms alone"],["Determination method","Hospital imaging (CT/MRI)","Hospital imaging (CT/MRI)"],["Field priority","Same: recognize, check glucose, document LKW time, transport rapidly","Same: recognize, check glucose, document LKW time, transport rapidly"]]}]},"c02":{"chapter":"c02","tables":[{"id":"c02_t01","title":"AEIOU-TIPS: Reversible Causes of Altered Mental Status","headers":["Letter","Cause"],"rows":[["A","Alcohol"],["E","Epilepsy/seizure (postictal state)"],["I","Insulin (hypoglycemia or hyperglycemia)"],["O","Overdose/opioids"],["U","Uremia/metabolic derangement"],["T","Trauma/temperature (hyperthermia/hypothermia)"],["I","Infection"],["P","Psychiatric"],["S","Stroke/shock"]]}]},"c03":{"chapter":"c03","tables":[{"id":"c03_t01","title":"DKA vs. HHS Comparison","headers":["Feature","DKA","HHS"],"rows":[["Glucose","≥200 mg/dL typically (can be <200 mg/dL — euglycemic DKA, ~10% of cases)","Often >600 mg/dL"],["Ketosis","Present — beta-hydroxybutyrate ≥3.0 mmol/L or urine ketones ≥2+","Minimal or absent"],["Acid-base status","Metabolic acidosis — pH <7.3 and/or bicarbonate <18 mEq/L","Near-normal pH/bicarbonate"],["Osmolality","Variable, less central to diagnosis","Significant hyperosmolality — >320 mOsm/kg"],["Typical patient","More classic in type 1 diabetes, but occurs in type 2 as well","More typical in older adults with type 2 diabetes"],["Onset","Faster, often over hours","Slower, often over days"],["Classic exam findings","Kussmaul respirations, fruity breath, vomiting/abdominal pain","Profound dehydration, prominent altered mental status/obtundation"],["Field management","Supportive care, IV fluids per protocol, airway protection, rapid transport","Supportive care, IV fluids per protocol, airway protection, rapid transport"]]},{"id":"c03_t02","title":"Hypoglycemia Symptom Progression","headers":["Severity","Findings"],"rows":[["Mild","Shakiness, diaphoresis, hunger, anxiety"],["Moderate","Irritability, poor coordination, difficulty concentrating"],["Severe","Confusion, combativeness, seizure, unresponsiveness"]]}]}}};
